// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';
import { actionExecution } from "@dynatrace-sdk/automation-utils";

export default async function ({ execution_id, action_execution_id }) {
  const actionEx = await actionExecution(action_execution_id);
  console.log(actionEx.loopItem.item)
  const status = actionEx.loopItem.item.Status.toUpperCase()
  console.log(status)

  if (status =="INPROGRESS") {
        console.log("Send Command Execution is still running, restarting again!");
        throw new Error("Send Command Execution is still running, restarting again!");
  } 

  return status;
}
